const express = require('express');
const jwt = require('jsonwebtoken'); // For JWT operations (verify, sign) 
require("dotenv").config();   // To read .env file variables in NodeJS environment. Easier to use dotenv package instead of hardcoding them into your codebase for security reasons and versioning control purposes etc..
const app = express();
app.use(express.json()); 
// Middleware function that validates incoming bearer tokens from the Authorization header, then verifies if they're signed with our secret key (from .env file). If so it passes them to next middle ware in line otherwise an error is returned and a message sent back via res object indicating unauthorized access.
app.use((req,res,next)=>{  // Middleware function that validates incoming bearer tokens from the Authorization header  
    const authHeader = req.headers['authorization'];    
    if (typeof authHeader !== 'undefined') {     
        const token = authHeader && authHeader.split('Bearer ')[1];  // Bearer <token>, we only want to extract the second part of string after "Bearer ". If not exist then it will return undefined and next middleware function is called again with error message in res object indicating unauthorized access
        if (typeof token !== 'undefined') {     
            jwt.verify(token, process.env.ACCESS_TOKEN_SECRET ,  // Verifying the JWT signature using our secret key and callback function to handle errors or successes in verification  
                (err) =>{      
                    if (err){   
                        return res.status(403).send('Unauthorized access!');    
                    }else {  // If token is valid then next middleware will be called otherwise it'll call again with error message in the response object indicating unauthorization  
                      next();     
                     }   
                });      
        } else{        
            return res.status(401).send('Unauthorized access!');     // If no token provided then authorize them and send an appropriate respond back to client 
          }          
    }else {  
             return res.status(403).send("Authorization header is not found!");      //If the Authorization Header doesnt exist in request, it means that user didnot provide any token so we should send an error message back to client 
        }    
});   
